        self.width = width
        self.height = height
        # Each cell holds either None or a Gem instance
        self.cells = [[None for _ in range(width)] for _ in range(height)]

    def is_valid_move(self, shape_matrix, offset_x, offset_y):
        for r, row in enumerate(shape_matrix):
            for c, cell in enumerate(row):
                if cell:
                    x = offset_x + c
                    y = offset_y + r
                    if x < 0 or x >= self.width or y < 0 or y >= self.height:
                        return False
                    if self.cells[y][x] is not None:
                        return False
        return True

