        del self.cells[row_index]
        self.cells.insert(0, [None for _ in range(self.width)])

    def check_lines(self):
        """Check for and clear full lines (bottom-up)."""
        lines_cleared = 0
        for row_index in reversed(range(self.height)):
            if all(self.cells[row_index]):
                self.clear_line(row_index)
                lines_cleared += 1
        return lines_cleared

