        # Reset previous matched flags
        for row in self.cells:
            for gem in row:
                if gem:
                    gem.matched = False

        total_matches = 0
        # Horizontal matches
        for r in range(self.height):
            c = 0
            while c < self.width:
                if self.cells[r][c] is None:
                    c += 1
                    continue
                color = self.cells[r][c].color
                run_len = 1
                for k in range(c+1, self.width):
                    if self.cells[r][k] and self.cells[r][k].color == color:
                        run_len += 1
                    else:
                        break
                if run_len >= 3:
                    for k in range(c, c+run_len):
                        self.cells[r][k].matched = True
                    total_matches += run_len
                c += run_len

        # Vertical matches
        for c in range(self.width):
            r = 0
            while r < self.height:
                if self.cells[r][c] is None:
                    r += 1
                    continue
                color = self.cells[r][c].color
                run_len = 1
                for k in range(r+1, self.height):
                    if self.cells[k][c] and self.cells[k][c].color == color:
                        run_len += 1
                    else:
                        break
                if run_len >= 3:
                    for k in range(r, r+run_len):
                        self.cells[k][c].matched = True
                    total_matches += run_len
                r += run_len

        return total_matches

    def clear_matches(self):
        """Clear matched gems and return the number of cleared gems."""
        cleared_count = 0
        for r in range(self.height):
            for c in range(self.width):
                if self.cells[r][c] and self.cells[r][c].matched:
                    self.cells[r][c] = None
                    cleared_count += 1
        return cleared_count

